export const 鎮宅發狂 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿＋左⟨括＋圈行三
    線(p => p.M(X(1.2), Z(1.0)).L(X(6.1), Z(0.9)));
    圈(0.9, 1.0);
    圈(6.4, 0.9);
    線(p => p.M(X(0.6), Z(3.0)).C(X(0.3), Z(3.6), X(0.3), Z(4.2), X(0.6), Z(4.7)), 0.36);
    for (const [x, z] of [[1.4, 2.7], [2.7, 2.8], [4.0, 2.7], [5.3, 2.8], [6.4, 2.7],
        [1.5, 4.1], [2.8, 4.2], [4.1, 4.1], [5.4, 4.2],
        [1.6, 5.5], [2.9, 5.6], [4.2, 5.5], [5.5, 5.6], [6.5, 5.5]])
        圈(x, z);
    // 厂寬桁
    線(p => p.M(X(0.8), Z(6.4)).L(X(6.7), Z(6.3)), 0.42);
    線(p => p.M(X(0.8), Z(6.45)).L(X(0.8), Z(7.4)));
    // 冎田複構：左工呂・中阝田・右目
    線(p => p.M(X(1.1), Z(7.6)).L(X(1.1), Z(9.7)), 0.34);
    線(p => p.M(X(0.7), Z(8.0)).L(X(1.6), Z(7.97)), 0.34);
    線(p => p.M(X(0.7), Z(9.4)).L(X(1.6), Z(9.37)), 0.34);
    線(p => p.M(X(1.9), Z(7.7)).L(X(1.9), Z(10.9)).L(X(3.2), Z(10.85))
        .L(X(3.2), Z(7.65)).L(X(1.85), Z(7.7)));
    線(p => p.M(X(2.0), Z(9.3)).L(X(3.1), Z(9.27)), 0.32);
    線(p => p.M(X(3.7), Z(7.6)).L(X(3.7), Z(10.8)), 0.36);
    線(p => p.M(X(3.75), Z(8.2)).C(X(4.1), Z(8.5), X(4.1), Z(9.0), X(3.75), Z(9.3)), 0.32);
    線(p => p.M(X(4.4), Z(7.7)).L(X(4.4), Z(10.0)).L(X(5.7), Z(9.95))
        .L(X(5.7), Z(7.65)).L(X(4.35), Z(7.7)));
    線(p => p.M(X(4.5), Z(8.85)).L(X(5.6), Z(8.82)), 0.32);
    線(p => p.M(X(5.05), Z(7.75)).L(X(5.03), Z(9.95)), 0.32);
    線(p => p.M(X(6.1), Z(7.6)).L(X(6.1), Z(10.7)).L(X(7.0), Z(10.65))
        .L(X(7.0), Z(7.55)).L(X(6.05), Z(7.6)));
    線(p => p.M(X(6.2), Z(9.1)).L(X(6.9), Z(9.07)), 0.32);
    // 力大撇
    線(p => p.M(X(1.6), Z(11.4)).L(X(3.3), Z(11.35)), 0.4);
    線(p => p.M(X(2.9), Z(11.4)).C(X(2.5), Z(13.0), X(1.9), Z(14.6), X(1.1), Z(15.9)), 0.44);
    線(p => p.M(X(3.3), Z(11.4)).C(X(3.4), Z(12.6), X(3.2), Z(13.7), X(2.7), Z(14.6))
        .C(X(2.5), Z(14.9), X(2.2), Z(15.1), X(1.9), Z(15.2)), 0.4);
    // 底田疊
    const 田 = (x0, z0) => {
        線(p => p.M(X(x0), Z(z0)).L(X(x0), Z(z0 + 2.2)).L(X(x0 + 2.2), Z(z0 + 2.15))
            .L(X(x0 + 2.2), Z(z0 - 0.05)).L(X(x0 - 0.05), Z(z0)));
        線(p => p.M(X(x0 + 0.1), Z(z0 + 1.1)).L(X(x0 + 2.1), Z(z0 + 1.07)), 0.32);
        線(p => p.M(X(x0 + 1.1), Z(z0 + 0.05)).L(X(x0 + 1.08), Z(z0 + 2.15)), 0.32);
    };
    田(4.2, 11.6);
    田(4.3, 14.5);
    線(p => p.M(X(4.3), Z(17.4)).L(X(4.3), Z(19.0)).L(X(6.5), Z(18.95))
        .L(X(6.5), Z(17.35)).L(X(4.25), Z(17.4)));
};
